//! `symphony init` — scaffold a WORKFLOW.md in the current directory.

use std::path::Path;

use super::InitArgs;

const LINEAR_TEMPLATE: &str = r#"---
# Symphony WORKFLOW.md — Linear + Claude Code
# Generated by `symphony init --tracker linear`

tracker:
  kind: linear
  api_key: $LINEAR_API_KEY
  project_slug: your-project-slug     # From Linear project URL
  active_states:
    - Todo
    - In Progress
  terminal_states:
    - Done
    - Canceled
    - Duplicate
  # done_state: Done                  # Uncomment to auto-transition on success

polling:
  interval_ms: 30000

workspace:
  root: ~/symphony-workspaces/my-project

hooks:
  after_create: |
    # Clone your repo into the workspace on first creation
    gh repo clone your-org/your-repo . -- --depth 50
    git checkout -b "symphony/$SYMPHONY_ISSUE_ID"
  before_run: |
    git add -A && git stash || true
    git fetch origin main
    git rebase origin/main || git rebase --abort
    git stash pop || true
  after_run: |
    git add -A
    git commit -m "$SYMPHONY_ISSUE_ID: $SYMPHONY_ISSUE_TITLE" || true
    git push -u origin "symphony/$SYMPHONY_ISSUE_ID" --force-with-lease || true
  # pr_feedback: |
  #   # Uncomment to enable PR review comment feedback loop
  #   PR_NUM=$(gh pr view "symphony/$SYMPHONY_ISSUE_ID" --json number -q '.number' 2>/dev/null)
  #   if [ -n "$PR_NUM" ]; then
  #     gh api "repos/your-org/your-repo/pulls/$PR_NUM/comments" \
  #       --jq '.[] | "**\(.user.login)**: \(.body)"' 2>/dev/null
  #   fi
  # after_session: |
  #   # Uncomment to capture session outcome (e.g. for conversation bridge)
  #   echo "$SYMPHONY_ISSUE_ID: $SYMPHONY_SESSION_OUTCOME (tokens: $SYMPHONY_TOKENS_TOTAL)"
  timeout_ms: 180000

agent:
  max_concurrent_agents: 2
  max_turns: 3

codex:
  command: claude --dangerously-skip-permissions

server:
  port: 8080

# profile:
#   role: "senior full-stack engineer"
#   consciousness: governed        # baseline | governed | autonomous
#   skills: [agentic-control-kernel, knowledge-graph-memory]
#   control_profile: governed      # baseline | governed | autonomous
#   context: "This is a monorepo with strict linting. Always run make check."
---

You are a senior engineer working on {{ issue.identifier }}: {{ issue.title }}.

## Control Metalayer
1. Read CLAUDE.md and AGENTS.md for project conventions
2. If `.symphony-pr-feedback.md` exists, resolve PR comments first
3. Follow: implement → test → lint → verify

{% if issue.description %}
## Issue Description
{{ issue.description }}
{% endif %}

{% if issue.labels %}
## Labels
{{ issue.labels | join: ", " }}
{% endif %}

## Instructions
1. Read the project structure and understand the codebase
2. Implement the requested changes following existing patterns
3. Write or update tests for your changes
4. Ensure the code compiles and lints cleanly
5. Keep changes focused — only modify what the ticket requires

{% if attempt %}
## Retry Attempt {{ attempt }}
Check git log for prior work. Resolve `.symphony-pr-feedback.md` comments first if present.
{% endif %}
"#;

