pub fn run_init(args: &InitArgs) -> anyhow::Result<()> {
    let output_path = &args.output;

    if output_path.exists() && !args.force {
        anyhow::bail!(
            "{} already exists. Use --force to overwrite.",
            output_path.display()
        );
    }

    let template = match args.tracker.as_str() {
        "linear" => LINEAR_TEMPLATE,
        "github" => GITHUB_TEMPLATE,
        "markdown" => MARKDOWN_TEMPLATE,
        other => {
            anyhow::bail!("unsupported tracker: '{other}'. Use 'linear', 'github', or 'markdown'.")
        }
    };

    std::fs::write(output_path, template)?;

    println!("Created {}", output_path.display());
    println!();
    println!("Next steps:");
    println!(
        "  1. Edit {} — fill in your project details",
        output_path.display()
    );
    if args.tracker != "markdown" {
        println!("  2. Set environment variables (e.g. LINEAR_API_KEY or GITHUB_TOKEN)");
    } else {
        println!("  2. Create issue .md files in your tasks/ directory");
    }
    println!("  3. Run: symphony validate {}", output_path.display());
    println!("  4. Run: symphony start {}", output_path.display());

    print_env_hint(&args.tracker, output_path);

    Ok(())
}

fn print_env_hint(tracker: &str, path: &Path) {
    println!();
    match tracker {
        "linear" => {
            println!("Required environment variables:");
            println!("  export LINEAR_API_KEY=lin_api_...");
            println!();
            println!("Quick test:");
            println!("  symphony run STI-123 --workflow-path {}", path.display());
        }
        "github" => {
            println!("Required environment variables:");
            println!("  export GITHUB_TOKEN=ghp_...");
            println!();
            println!("Quick test:");
            println!(
                "  symphony run 'owner/repo#42' --workflow-path {}",
                path.display()
            );
        }
        "markdown" => {
            println!("No environment variables required!");
            println!();
            println!("Create an issue file (e.g. tasks/task-001.md):");
            println!("  ---");
            println!("  id: TASK-001");
            println!("  title: My first task");
            println!("  state: Todo");
            println!("  priority: 1");
            println!("  labels: [feature]");
            println!("  ---");
            println!("  Description of the task.");
            println!();
            println!("Quick test:");
            println!("  symphony run TASK-001 --workflow-path {}", path.display());
        }
        _ => {}
    }
}
